inputs.javascriptFunction:
const fetch = require("node-fetch");

const DB_BASE = "https://ruler:ruler@192.168.57.254:5984/new_pine";
const FETCH_URL = `${DB_BASE}/_all_docs?include_docs=true`;

function stableSortObject(obj) {
  if (obj === null || typeof obj !== "object") return obj;
  if (Array.isArray(obj)) return obj.map(stableSortObject);

  return Object.keys(obj)
    .sort()
    .reduce((acc, key) => {
      acc[key] = stableSortObject(obj[key]);
      return acc;
    }, {});
}

function stableValue(value) {
  if (value === null || value === undefined) return "";
  if (typeof value !== "object") return String(value);
  return JSON.stringify(stableSortObject(value));
}

async function loadDocuments() {
  const res = await fetch(FETCH_URL, {
    method: "GET",
    headers: {
      "Accept": "application/json"
    }
  });

  if (!res.ok) {
    const txt = await res.text();
    throw new Error(`CouchDB fetch failed: ${res.status} ${res.statusText} - ${txt}`);
  }

  const data = await res.json();

  const docs = (data.rows || [])
    .map(row => row.doc)
    .filter(Boolean)
    .filter(doc => doc._id && !String(doc._id).startsWith("_design/"));

  const documents = docs.map((doc) => {
    const sortedKeys = Object.keys(doc).sort();

    const pageContent = sortedKeys
      .map((key) => `${key}: ${stableValue(doc[key])}`)
      .join("\n");

    return {
      id: String(doc._id),   // stable unique id
      pageContent,
      metadata: {
        source: `couchdb:new_pine:${doc._id}`,   // MUST not be null
        doc_id: String(doc._id),
        doc_rev: String(doc._rev || ""),
        db_name: "new_pine"
      }
    };
  });

  console.log("Documents prepared:", documents.length);

  return documents;
}

return loadDocuments();
